SELECT DISTINCT data_source
FROM datasets
WHERE type = 'gene expression';

SELECT AVG(expression_level) AS average_expression_level
FROM genomics_data
WHERE gene_id = 'GENE001';

SELECT dataset_id, MIN(expression_level) AS min_expression_level, MAX(expression_level) AS max_expression_level
FROM genomics_data
GROUP BY dataset_id;

SELECT gene_id, description
FROM genes
GROUP BY gene_id, description;

SELECT collaborator
FROM genomics_data_collaborations
WHERE genomics_data_id = 0;

SELECT gene_id
FROM genomics_data
WHERE log_fold_change > 30;
